import{_ as e,o as t,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const l="/images/screenshots/console-copy-api-request.png",_=JSON.parse('{"title":"网络与连接","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/network.md","filePath":"troubleshooting/network.md","lastUpdated":1782208943000}'),s={name:"troubleshooting/network.md"};function r(n,a,c,p,d,h){return t(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="网络与连接" tabindex="-1">网络与连接 <a class="header-anchor" href="#网络与连接" aria-label="Permalink to &quot;网络与连接&quot;">​</a></h1><h2 id="连接超时" tabindex="-1">连接超时 <a class="header-anchor" href="#连接超时" aria-label="Permalink to &quot;连接超时&quot;">​</a></h2><p>遇到连接超时、请求失败时，先用控制台里已经生成好的 API 请求做验证。</p><p><img src="'+l+'" alt="在控制台复制 API 请求" loading="lazy"></p><p>操作方法：</p><ul><li>登录 CCWSPro 控制台。</li><li>进入「概览」页面。</li><li>找到右侧「首个 API 请求」卡片。</li><li>点击右上角「复制」。</li><li>把复制出来的请求粘贴到终端或 PowerShell 里执行。</li></ul><div class="warning custom-block"><p class="custom-block-title">注意</p><p>复制出来的请求里会包含你的 API Key，不要发到群聊、截图、公开仓库或文章正文里。</p></div><p>如果复制出来的请求能正常返回内容，说明平台接口、Key 和模型调用基本可用。后续再检查 Codex、CC Switch 或其他工具里的配置是否填写一致。</p><div class="danger custom-block"><p class="custom-block-title">不要这样测</p><p>不要用 HEAD 请求去测 <code>/v1</code> 地址是否可用。<code>/v1</code> 是 API 前缀，不是普通网页地址；HEAD 请求不能代表真实模型调用是否可用。</p></div><h2 id="域名解析检查" tabindex="-1">域名解析检查 <a class="header-anchor" href="#域名解析检查" aria-label="Permalink to &quot;域名解析检查&quot;">​</a></h2><p>如果控制台复制的 API 请求完全连不上，可以再检查基础域名是否能解析：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> www.ccws.pro</span></span></code></pre></div><p><code>ping</code> 只能辅助判断域名解析和本机网络状态，不能替代真实 API 请求验证。</p><h2 id="dns-问题" tabindex="-1">DNS 问题 <a class="header-anchor" href="#dns-问题" aria-label="Permalink to &quot;DNS 问题&quot;">​</a></h2><p>如果浏览器能打开官网，但命令行无法访问接口，可能是 DNS 或代理配置不一致。</p><p>建议：</p><ul><li>切换网络环境。</li><li>关闭或调整代理。</li><li>检查系统 DNS。</li><li>在终端里单独验证 <code>www.ccws.pro</code>。</li></ul><h2 id="代理冲突" tabindex="-1">代理冲突 <a class="header-anchor" href="#代理冲突" aria-label="Permalink to &quot;代理冲突&quot;">​</a></h2><p>如果使用了代理工具，请确认 HTTP_PROXY、HTTPS_PROXY、ALL_PROXY 等环境变量没有误伤本地工具。</p>',19)])])}const b=e(s,[["render",r]]);export{_ as __pageData,b as default};
